def capacity_values(items: list[tuple[int, int]], capacity: int) -> list[int]:
    best = [0] * (capacity + 1)
    for value, weight in items:
        for room in range(capacity, weight - 1, -1):
            best[room] = max(best[room], best[room - weight] + value)
    return best

